function Field() {
  const [open, setOpen] = useState(false);
  return (
    <span
      onMouseEnter={() => setOpen(true)}
      onMouseLeave={() => setOpen(false)}
      onKeyDown={(e) => e.key === "Escape" && setOpen(false)}
    >
      <button
        aria-describedby="hint"
        onFocus={() => setOpen(true)}
        onBlur={() => setOpen(false)}
      >
        Username
      </button>
      {open && (
        // Tooltip lives inside the hover target, so it stays until dismissed
        <span id="hint" role="tooltip">Must be 3–20 characters.</span>
      )}
    </span>
  );
}

function Modal({ onClose, children }) {
  return (
    <div
      role="dialog"
      aria-modal="true"
      onKeyDown={(e) => e.key === "Escape" && onClose()}
    >
      {children}
      <button onClick={onClose}>Close</button>
    </div>
  );
}

function Modal({ children }) {
  // No way out: focus is trapped with no Escape handler or close control
  return (
    <div
      role="dialog"
      aria-modal="true"
      onKeyDown={(e) => e.key === "Tab" && e.preventDefault()}
    >
      {children}
    </div>
  );
}

// Shortcut only fires while the editor has focus
<div
  role="textbox"
  onKeyDown={(e) => {
    if (e.key === "b" && (e.ctrlKey || e.metaKey)) toggleBold();
  }}
/>

// Fires on any "b" keypress anywhere on the page
useEffect(() => {
  const onKey = (e) => { if (e.key === "b") toggleBold(); };
  document.addEventListener("keydown", onKey);
  return () => document.removeEventListener("keydown", onKey);
}, []);

function SessionTimer({ onExtend }) {
  return (
    <div role="alertdialog" aria-label="Session expiring">
      <p>Your session expires in 60 seconds.</p>
      <button onClick={onExtend}>Stay signed in</button>
    </div>
  );
}

