@keyframes pulse {
  from { opacity: 1; }
  to   { opacity: 0.6; }
}
.alert { animation: pulse 2s ease-in-out infinite; }

/* ~10 flashes per second — a seizure risk */
@keyframes strobe {
  50% { background: #fff; }
}
.alert { animation: strobe 0.1s steps(1) infinite; }

@keyframes fade {
  from { opacity: 1; }
  to   { opacity: 0.7; }
}
.badge { animation: fade 1.5s ease-in-out infinite alternate; }

/* Flashes well over 3 times per second */
@keyframes blinkFast {
  50% { opacity: 0; }
}
.badge { animation: blinkFast 0.15s steps(1) infinite; }

.panel { transition: transform 0.4s ease; }
@media (prefers-reduced-motion: reduce) {
  .panel { transition: none; }
}

